import { Component, OnInit, OnDestroy, inject } from '@angular/core';
import { FormBuilder, FormGroup, FormArray, Validators, FormControl } from '@angular/forms';
import { Router, ActivatedRoute } from '@angular/router';
import { CommonModule } from '@angular/common';
import { ReactiveFormsModule } from '@angular/forms';
import { RouterModule } from '@angular/router';
import { Subscription, lastValueFrom } from 'rxjs';

import { AuthService } from '../../services/timbrature-auth.adapter';
import { TimbratureService } from '../../services/timbrature.service';
import { CompanyService } from '../../services/company.service';
import { Timbratura, RichiestaModificaPayload, Company, User } from '../../models';
import { LUCIDE_ICONS, LucideAngularModule } from 'lucide-angular';

interface Posizione {
  lat: number;
  lng: number;
  indirizzo?: string;
  timestamp: Date;
  accuracy?: number;
}

@Component({
  selector: 'app-crea-timbratura',
  standalone: true,
  imports: [CommonModule, ReactiveFormsModule, RouterModule, LucideAngularModule],
  templateUrl: './crea-timbratura.component.html',
  styleUrls: ['./crea-timbratura.component.css']
})
export class CreaTimbraturaComponent implements OnInit, OnDestroy {

  private fb = inject(FormBuilder);
  private timbratureService = inject(TimbratureService);
  private authService = inject(AuthService);
  private companyService = inject(CompanyService);
  private router = inject(Router);
  private route = inject(ActivatedRoute);

  // Form
  timbraturaForm: FormGroup;
  
  // Stato UI
  isLoading = false;
  errorMessage = '';
  successMessage = '';
  ottenendoPosizione = false;
  caricandoTimbraturaPrecedente = false; // <-- Aggiunto

  // Dati
  currentUser: User | null = null;
  currentCompany: Company | null = null;
  posizioneAttuale: Posizione | null = null;
  posizioneValida = false;
  nearestPoint: any = null;
  distanceToNearest: number | null = null;
  puntoSelezionato: any = null;

  // Modalità modifica
  isEditMode = false;
  timbraturaId: string | null = null;
  timbraturaOriginale: Timbratura | null = null;

  // Copia dal giorno precedente
  timbraturaPrecedente: Timbratura | null = null;
  timbraturaPrecedenteDisponibile = false;

  // Controllo timbratura esistente per data selezionata (aggiunto)
  existingTimbraturaForDate: Timbratura | null = null;
  hasTimbraturaForSelectedDate = false;

  // Sottoscrizioni
  private subs = new Subscription();

  // Validatori come arrow function
  private noFutureDateValidator = (control: any) => {
    if (!control.value) return null;
    return new Date(control.value) > new Date() ? { futureDate: true } : null;
  };

  private noFutureTimeValidator = (control: any) => {
    if (!control.value) return null;
    const data = this.timbraturaForm?.get('data')?.value;
    if (data !== new Date().toISOString().split('T')[0]) return null;
    const now = new Date();
    const current = `${now.getHours().toString().padStart(2,'0')}:${now.getMinutes().toString().padStart(2,'0')}`;
    return control.value > current ? { futureTime: true } : null;
  };

  private timeRangeValidator = (group: FormGroup) => {
    const start = group.get('ora_inizio')?.value;
    const end = group.get('ora_fine')?.value;
    if (start && end && end <= start) return { invalidTimeRange: true };
    return null;
  };

  private pauseTimeRangeValidator = (group: FormGroup) => {
    const start = group.get('inizio')?.value;
    const end = group.get('fine')?.value;
    if (start && end && end <= start) return { invalidPauseTimeRange: true };
    return null;
  };

constructor() {
  this.timbraturaForm = this.createForm();
}

ngOnInit(): void {
  // Data odierna di default
  this.timbraturaForm.patchValue({ data: new Date().toISOString().split('T')[0] });

  // Sottoscrizione utente
this.subs.add(
  this.authService.currentUser$.subscribe(user => {
    this.currentUser = user as any;
    const companyId = this.authService.companyId;
    if (companyId) {
      this.loadCompanyAndInit(companyId);
    }
  })
);

  // Leggi il parametro id dalla route
  this.subs.add(
    this.route.paramMap.subscribe(params => {
      const id = params.get('id');
      if (id) {
        this.isEditMode = true;
        this.timbraturaId = id;
        this.loadTimbraturaForEdit(id);
      } else {
        this.isEditMode = false;
        this.timbraturaId = null;
      }
    })
  );

  // Quando cambia data, controlla se esiste già timbratura
  this.timbraturaForm.get('data')?.valueChanges.subscribe(date => {
    this.checkExistingTimbraturaForDate(date).catch(console.error);
    this.timbraturaForm.get('ora_inizio')?.updateValueAndValidity();
    this.timbraturaForm.get('ora_fine')?.updateValueAndValidity();
    this.revalidateAllPauses();
  });
}

  ngOnDestroy(): void {
    this.subs.unsubscribe();
  }

  // --- Inizializzazione ---
  private async loadCompanyAndInit(companyId: string): Promise<void> {
    try {
      this.currentCompany = await lastValueFrom(this.companyService.getById(companyId));
      if (!this.isEditMode) {
        await this.checkPreviousDayTimbratura();
        await this.checkExistingTimbraturaForDate(this.timbraturaForm.value.data);
      }
    } catch (err) {
      console.error('Errore caricamento azienda', err);
    }
  }

  private async loadTimbraturaForEdit(id: string): Promise<void> {
    this.isLoading = true;
    try {
      const timbratura = await lastValueFrom(this.timbratureService.getTimbraturaBId(id));
      if (!timbratura) throw new Error('Timbratura non trovata');

      if (!this.authService.hasRole('admin') && timbratura.user_id !== this.currentUser?.id) {
        this.errorMessage = 'Non hai i permessi per modificare questa timbratura';
        setTimeout(() => this.router.navigate(['/lista-timbrature']), 2000);
        return;
      }

      this.timbraturaOriginale = timbratura;
      this.popolaFormConDatiEsistenti(timbratura);
    } catch (err) {
      this.errorMessage = 'Errore nel caricamento della timbratura';
      console.error(err);
    } finally {
      this.isLoading = false;
    }
  }

  // --- Controllo timbratura esistente per data ---
  private async checkExistingTimbraturaForDate(dateStr: string): Promise<void> {
    try {
      this.existingTimbraturaForDate = null;
      this.hasTimbraturaForSelectedDate = false;
      if (!this.currentUser || !dateStr) return;

      const timbrature = await lastValueFrom(this.timbratureService.fetchTimbrature({ userId: this.currentUser.id }));
      const target = new Date(dateStr);
      target.setHours(0,0,0,0);

      const found = timbrature.find(t => {
        const d = new Date(t.start_ts);
        d.setHours(0,0,0,0);
        return d.getTime() === target.getTime();
      }) || null;

      if (found) {
        this.existingTimbraturaForDate = found;
        this.hasTimbraturaForSelectedDate = true;
      }
    } catch (err) {
      console.error('[CreaTimbratura] checkExistingTimbraturaForDate error', err);
      this.hasTimbraturaForSelectedDate = false;
      this.existingTimbraturaForDate = null;
    }
  }

  // --- Popola form con dati esistenti (per modifica) ---
  private popolaFormConDatiEsistenti(timbratura: Timbratura): void {
    const start = new Date(timbratura.start_ts);
    const end = timbratura.end_ts ? new Date(timbratura.end_ts) : null;
    this.timbraturaForm.patchValue({
      data: start.toISOString().split('T')[0],
      ora_inizio: start.toTimeString().substring(0, 5),
      ora_fine: end ? end.toTimeString().substring(0, 5) : '',
      notes: timbratura.notes || ''
    });

    // Pause
    while (this.pause.length) this.pause.removeAt(0);
    if (timbratura.breaks && Array.isArray(timbratura.breaks) && timbratura.breaks.length) {
      timbratura.breaks.forEach((b: any) => {
        const bs = new Date(b.start);
        const be = new Date(b.end);
        this.pause.push(this.fb.group({
          inizio: [bs.toTimeString().substring(0,5), this.noFutureTimeValidator],
          fine: [be.toTimeString().substring(0,5), this.noFutureTimeValidator]
        }, { validators: this.pauseTimeRangeValidator }));
      });
    } else {
      this.pause.push(this.creaPausaGroup());
    }

    // Posizione
    if (timbratura.locations && timbratura.locations.length) {
      const loc = timbratura.locations[0];
      this.posizioneAttuale = {
        lat: loc.lat,
        lng: loc.lng,
        indirizzo: loc.address,
        timestamp: new Date(loc.timestamp),
        accuracy: 0
      };
      this.posizioneValida = true;
    }
  }

  // --- Form ---
  private createForm(): FormGroup {
    return this.fb.group({
      data: ['', [Validators.required, this.noFutureDateValidator]],
      ora_inizio: ['', [Validators.required, this.noFutureTimeValidator]],
      ora_fine: ['', this.noFutureTimeValidator],
      notes: [''],
      pause: this.fb.array([this.creaPausaGroup()])
    }, { validators: this.timeRangeValidator });
  }

  private creaPausaGroup(): FormGroup {
    return this.fb.group({
      inizio: ['', this.noFutureTimeValidator],
      fine: ['', this.noFutureTimeValidator]
    }, { validators: this.pauseTimeRangeValidator });
  }

  // Getter
  get pause(): FormArray { return this.timbraturaForm.get('pause') as FormArray; }
  get isSelectedDateToday(): boolean {
    return this.timbraturaForm.value.data === new Date().toISOString().split('T')[0];
  }
  get maxDate(): string {  // <-- Aggiunto
    return new Date().toISOString().split('T')[0];
  }

  // Getter per errori del form
  get hasTimeRangeError(): boolean {
    return this.timbraturaForm.hasError('invalidTimeRange');
  }
  get timeRangeErrorMessage(): string {
    return this.timbraturaForm.getError('invalidTimeRange') ? 'L\'ora di uscita deve essere successiva all\'ora di ingresso' : '';
  }

  // Metodi pause
  aggiungiPausa(): void { this.pause.push(this.creaPausaGroup()); }
  rimuoviPausa(index: number): void { if (this.pause.length > 1) this.pause.removeAt(index); }
  isPauseUsed(index: number): boolean {
    const g = this.pause.at(index);
    return !!(g.get('inizio')?.value || g.get('fine')?.value);
  }
  canRemovePause(index: number): boolean {
    return this.pause.length > 1 && this.isPauseUsed(index);
  }
  getPausaControl(index: number, field: string): FormControl { // <-- Aggiunto
    return this.pause.at(index).get(field) as FormControl;
  }
  hasPauseTimeError(index: number): boolean { // <-- Aggiunto
    return this.pause.at(index).hasError('invalidPauseTimeRange');
  }
  getPauseTimeErrorMessage(index: number): string { // <-- Aggiunto
    return this.pause.at(index).getError('invalidPauseTimeRange') ? 'La fine pausa deve essere successiva all\'inizio pausa' : '';
  }
  hasPauseErrors(): boolean { // <-- Aggiunto
    for (let i = 0; i < this.pause.length; i++) {
      if (this.pause.at(i).invalid) return true;
    }
    return false;
  }
  private revalidateAllPauses(): void {
    this.pause.controls.forEach(g => {
      g.get('inizio')?.updateValueAndValidity();
      g.get('fine')?.updateValueAndValidity();
    });
  }

  // --- Copia dal giorno precedente ---
  private async checkPreviousDayTimbratura(): Promise<void> {
    if (!this.currentUser) return;
    try {
      const timbrature = await lastValueFrom(this.timbratureService.fetchTimbrature({ userId: this.currentUser.id }));
      const giorniChiusura = this.currentCompany?.closed_days ?? [0, 6];
      let giornoPrec = new Date();
      giornoPrec.setDate(giornoPrec.getDate() - 1);
      while (giorniChiusura.includes(giornoPrec.getDay()) && giornoPrec > new Date(Date.now() - 7*24*60*60*1000)) {
        giornoPrec.setDate(giornoPrec.getDate() - 1);
      }
      const target = giornoPrec.toISOString().split('T')[0];
      this.timbraturaPrecedente = timbrature.find(t => new Date(t.start_ts).toISOString().split('T')[0] === target) || null;
      this.timbraturaPrecedenteDisponibile = !!this.timbraturaPrecedente;
    } catch (err) {
      console.error('Errore verifica timbratura precedente', err);
    }
  }

  async copiaGiornoPrecedente(): Promise<void> {
    if (!this.timbraturaPrecedente) return;
    this.caricandoTimbraturaPrecedente = true; // <-- Attivato
    try {
      const t = this.timbraturaPrecedente;
      const start = new Date(t.start_ts);
      const end = t.end_ts ? new Date(t.end_ts) : null;
      this.timbraturaForm.patchValue({
        ora_inizio: start.toTimeString().substring(0,5),
        ora_fine: end ? end.toTimeString().substring(0,5) : '',
        notes: t.notes || ''
      });
      // Pause
      while (this.pause.length) this.pause.removeAt(0);
      if (t.breaks && Array.isArray(t.breaks) && t.breaks.length) {
        t.breaks.forEach((b: any) => {
          const bs = new Date(b.start);
          const be = new Date(b.end);
          this.pause.push(this.fb.group({
            inizio: [bs.toTimeString().substring(0,5), this.noFutureTimeValidator],
            fine: [be.toTimeString().substring(0,5), this.noFutureTimeValidator]
          }, { validators: this.pauseTimeRangeValidator }));
        });
      } else {
        this.pause.push(this.creaPausaGroup());
      }
      this.successMessage = 'Dati copiati dal giorno precedente!';
      setTimeout(() => this.successMessage = '', 3000);
    } catch (err) {
      console.error('Errore copia', err);
    } finally {
      this.caricandoTimbraturaPrecedente = false; // <-- Disattivato
    }
  }

  // --- Geolocalizzazione ---
  ottieniPosizione(): void {
    this.ottenendoPosizione = true;
    this.errorMessage = '';
    navigator.geolocation.getCurrentPosition(
      (pos) => {
        this.posizioneAttuale = {
          lat: pos.coords.latitude,
          lng: pos.coords.longitude,
          accuracy: pos.coords.accuracy,
          timestamp: new Date()
        };
        this.verificaPosizioneRispettoPunti();
        this.ottenendoPosizione = false;
      },
      (err) => {
        this.errorMessage = `Errore geolocalizzazione: ${err.message}`;
        this.ottenendoPosizione = false;
      },
      { enableHighAccuracy: true, timeout: 10000 }
    );
  }

  private verificaPosizioneRispettoPunti(): void {
    if (!this.posizioneAttuale || this.currentCompany?.timbratura_type !== 'punti') return;
    const points = (this.currentCompany as any).punch_points || [];
    let nearest: any = null;
    let minDist = Infinity;
    for (const pt of points) {
      const d = this.distanzaMetri(
        this.posizioneAttuale.lat, this.posizioneAttuale.lng,
        Number(pt.lat), Number(pt.lng)
      );
      if (d < minDist) {
        minDist = d;
        nearest = pt;
      }
    }
    this.nearestPoint = nearest;
    this.distanceToNearest = minDist === Infinity ? null : Math.round(minDist);
    this.posizioneValida = this.nearestPoint && minDist <= (this.nearestPoint.radius_m || 50);
  }

  selezionaPunto(punto: any): void {
    this.puntoSelezionato = punto;
    this.posizioneValida = true;
    this.posizioneAttuale = {
      lat: Number(punto.lat),
      lng: Number(punto.lng),
      timestamp: new Date(),
      accuracy: 0
    };
    this.successMessage = `Punto selezionato: ${punto.name}`;
    setTimeout(() => this.successMessage = '', 3000);
  }

  deselezionaPunto(): void { this.puntoSelezionato = null; this.posizioneValida = false; }

  private distanzaMetri(lat1: number, lon1: number, lat2: number, lon2: number): number {
    const R = 6371e3;
    const φ1 = lat1 * Math.PI/180;
    const φ2 = lat2 * Math.PI/180;
    const Δφ = (lat2-lat1) * Math.PI/180;
    const Δλ = (lon2-lon1) * Math.PI/180;
    const a = Math.sin(Δφ/2) * Math.sin(Δφ/2) +
              Math.cos(φ1) * Math.cos(φ2) *
              Math.sin(Δλ/2) * Math.sin(Δλ/2);
    const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1-a));
    return R * c;
  }

  // --- Calcoli ore ---
  calcolaOreTotali(): number { // <-- Aggiunto
    const f = this.timbraturaForm.value;
    if (!f.ora_inizio || !f.ora_fine) return 0;
    const inizio = new Date(`2000-01-01T${f.ora_inizio}`);
    const fine = new Date(`2000-01-01T${f.ora_fine}`);
    return (fine.getTime() - inizio.getTime()) / (1000*60*60);
  }

  calcolaPauseTotali(): number { // <-- Aggiunto
    const f = this.timbraturaForm.value;
    let pause = 0;
    f.pause.forEach((p: any) => {
      if (p.inizio && p.fine) {
        const pi = new Date(`2000-01-01T${p.inizio}`);
        const pf = new Date(`2000-01-01T${p.fine}`);
        pause += (pf.getTime() - pi.getTime()) / (1000*60*60);
      }
    });
    return pause;
  }

  calcolaLavoroEffettivo(): number {
    return Math.max(0, this.calcolaOreTotali() - this.calcolaPauseTotali());
  }

  formattaOreMinuti(ore: number): string { // <-- Aggiunto
    const h = Math.floor(ore);
    const m = Math.round((ore - h) * 60);
    if (h === 0 && m === 0) return '0h';
    if (h === 0) return `${m}m`;
    if (m === 0) return `${h}h`;
    return `${h}h ${m}m`;
  }

  // --- Costruzione dati timbratura ---
  private buildTimbraturaData(): Partial<Timbratura> {
    const f = this.timbraturaForm.value;
    const start = new Date(`${f.data}T${f.ora_inizio}`);
    const end = f.ora_fine ? new Date(`${f.data}T${f.ora_fine}`) : null;
    const breaks = f.pause
      .filter((p: any) => p.inizio && p.fine)
      .map((p: any) => ({
        start: new Date(`${f.data}T${p.inizio}`).toISOString(),
        end: new Date(`${f.data}T${p.fine}`).toISOString()
      }));
    const locations = this.posizioneAttuale ? [{
      lat: this.posizioneAttuale.lat,
      lng: this.posizioneAttuale.lng,
      address: this.posizioneAttuale.indirizzo,
      timestamp: this.posizioneAttuale.timestamp.toISOString()
    }] : null;
    const total_minutes = Math.round(this.calcolaLavoroEffettivo() * 60);
    return {
      start_ts: start.toISOString(),
      end_ts: end?.toISOString() || null,
      breaks: breaks.length ? breaks : null,
      locations,
      notes: f.notes || null,
      total_minutes,
      company_id: this.currentCompany?.id || this.currentUser?.company_id || '',
      user_id: this.currentUser?.id || ''
    };
  }

  // --- Salvataggio / invio richiesta ---
  async onSubmit(): Promise<void> {
    if (this.timbraturaForm.invalid) {
      this.timbraturaForm.markAllAsTouched();
      return;
    }

    this.isLoading = true;
    this.errorMessage = '';
    this.successMessage = '';

    try {
      // Controllo timbratura doppia (se non admin e non modifica)
      if (!this.authService.hasRole('admin') && !this.isEditMode) {
        const exists = await this.timbratureService.hasTimbraturaPerGiorno(
          this.currentUser!.id,
          this.timbraturaForm.value.data,
          this.timbraturaOriginale?.id
        );
        if (exists) throw new Error('Hai già una timbratura per questa data');
      }

      // Controllo geolocalizzazione se necessario
      if (this.currentCompany?.timbratura_type === 'punti') {
        const points = (this.currentCompany as any).punch_points || [];
        if (!points.length) throw new Error('Nessun punto di timbratura configurato');
        if (!this.posizioneAttuale && !this.puntoSelezionato) {
          throw new Error('Devi prima ottenere la posizione o selezionare un punto');
        }
        if (!this.posizioneValida && !this.puntoSelezionato) {
          throw new Error('Posizione non valida rispetto ai punti di timbratura');
        }
      }

      if (this.isEditMode) {
        await this.handleEdit();
      } else {
        await this.handleCreate();
      }
    } catch (err: any) {
      this.errorMessage = err.message || 'Errore durante il salvataggio';
      console.error(err);
    } finally {
      this.isLoading = false;
    }
  }

  private async handleCreate(): Promise<void> {
    const data = this.buildTimbraturaData() as Timbratura;
    await lastValueFrom(this.timbratureService.creaTimbratura(data));
    this.successMessage = 'Timbratura creata con successo!';
    setTimeout(() => this.router.navigate(['/lista-timbrature']), 1500);
  }

  private async handleEdit(): Promise<void> {
    if (!this.timbraturaOriginale || !this.currentUser || !this.currentCompany) {
      throw new Error('Dati mancanti per la modifica');
    }
    const nuoviDati = this.buildTimbraturaData() as Timbratura;
    nuoviDati.id = this.timbraturaOriginale.id;

    if (this.authService.hasRole('admin')) {
      await lastValueFrom(this.timbratureService.aggiornaTimbratura(this.timbraturaOriginale.id!, nuoviDati));
      this.successMessage = 'Timbratura aggiornata!';
      setTimeout(() => this.router.navigate(['/lista-timbrature']), 1500);
    } else {
      const payload: RichiestaModificaPayload = {
        timbratura_id: this.timbraturaOriginale.id!,
        user_id: this.currentUser.id,
        company_id: this.currentCompany.id,
        requested_changes: nuoviDati,
        original_data: this.timbraturaOriginale,
        reason: 'Richiesta di modifica'
      };
      await this.timbratureService.creaRichiestaModifica(payload);
      this.successMessage = 'Richiesta di modifica inviata!';
      setTimeout(() => this.router.navigate(['/lista-timbrature']), 2000);
    }
  }

  // --- Metodi helper per template ---
  getSubmitButtonText(): string {
    if (this.isLoading) return 'Salvando...';
    if (this.isEditMode) {
      return this.authService.hasRole('admin') ? 'Salva Modifiche' : 'Invia Richiesta';
    }
    return 'Salva Timbratura';
  }

  pointLabel(pt: any): string {
    return pt?.name || pt?.address || 'Punto';
  }

  distanceToPoint(pt: any): number | null {
    if (!this.posizioneAttuale) return null;
    return Math.round(this.distanzaMetri(
      this.posizioneAttuale.lat, this.posizioneAttuale.lng,
      Number(pt.lat), Number(pt.lng)
    ));
  }

  isInsidePoint(pt: any): boolean {
    const d = this.distanceToPoint(pt);
    return d !== null && d <= (pt.radius_m || 50);
  }

  getPuntiNelRaggio(): any[] {
    if (!this.posizioneAttuale || this.currentCompany?.timbratura_type !== 'punti') return [];
    return ((this.currentCompany as any).punch_points || []).filter((pt: any) => this.isInsidePoint(pt));
  }

  isPuntoSelezionato(punto: any): boolean {
    return this.puntoSelezionato && this.puntoSelezionato.id === punto.id;
  }

get isAdmin(): boolean { return this.authService.hasRole('admin'); }
get isManager(): boolean { return this.authService.hasRole('manager'); }
get isEmployee(): boolean { return this.authService.hasRole('employee'); }

}
